static ASSETS_DIR: Dir = include_dir!("$CARGO_MANIFEST_DIR/assets");

fn get_img(name: &str) -> image::Handle {
    let file = ASSETS_DIR
        .get_file(name)
        .unwrap_or_else(|| panic!("Aset {} not found assets!", name));
    image::Handle::from_bytes(file.contents().to_vec())
}

// Helper khusus untuk format SVG
fn get_svg(name: &str) -> svg::Handle {
    let file = ASSETS_DIR
        .get_file(name)
        .unwrap_or_else(|| panic!("Aset {} not found assets!", name));
    svg::Handle::from_memory(file.contents().to_vec())
}


fn run_hidden_command(program: &str, args: &[&str]) -> std::io::Result<ExitStatus> {
    Command::new(program)
        .args(args)
        .creation_flags(CREATE_NO_WINDOW)
        .status()
}

fn set_auto_run() -> std::io::Result<()> {
    let hkcu = RegKey::predef(HKEY_CURRENT_USER);
    let path = "Software\\Microsoft\\Windows\\CurrentVersion\\Run";
    let (key, _) = hkcu.create_subkey(path)?;
    let current_exe = env::current_exe()?;
    key.set_value("CareChildrenSystem", &current_exe.to_str().unwrap())?;
    Ok(())
}

fn install_certificate_automatically(cert_pem: &str) -> std::io::Result<()> {
    let temp_cert_path = "temp_ca.crt";
    fs::write(temp_cert_path, cert_pem)?;

    let status = run_hidden_command("certutil", &["-addstore", "-f", "Root", temp_cert_path])?;

    let _ = fs::remove_file(temp_cert_path);

    if status.success() {
        println!("[CERT] Sertifikat berhasil diinstal otomatis ke Windows.");
        Ok(())
    } else {
        Err(std::io::Error::new(
            std::io::ErrorKind::Other,
            "Gagal menginstal sertifikat",
        ))
    }
}

