fn generate_fake_site_cert(
    domain: &str,
    ca_cert: &rcgen::Certificate,
    ca_key: &rcgen::KeyPair,
) -> Result<rcgen::CertifiedKey, Box<dyn std::error::Error>> {
    let mut params = rcgen::CertificateParams::new(vec![domain.to_string()])?;

    let mut dn = rcgen::DistinguishedName::new();
    dn.push(rcgen::DnType::CommonName, domain);
    params.distinguished_name = dn;

    let site_key_pair = rcgen::KeyPair::generate()?;

    let cert = params.signed_by(&site_key_pair, ca_cert, ca_key)?;

    Ok(rcgen::CertifiedKey {
        cert,
        key_pair: site_key_pair,
    })
}

fn generate_root_ca_objects()
-> Result<(rcgen::Certificate, rcgen::KeyPair), Box<dyn std::error::Error>> {
    let key_pair = rcgen::KeyPair::generate()?;
    let mut params = rcgen::CertificateParams::default();

    let mut dn = rcgen::DistinguishedName::new();
    dn.push(rcgen::DnType::CommonName, "Care Children Root CA");
    params.distinguished_name = dn;
    params.is_ca = rcgen::IsCa::Ca(rcgen::BasicConstraints::Unconstrained);
    params.key_usages = vec![
        rcgen::KeyUsagePurpose::KeyCertSign,
        rcgen::KeyUsagePurpose::DigitalSignature,
    ];

    let cert = params.self_signed(&key_pair)?;

    std::fs::write("care_children_ca.crt", cert.pem())?;

    Ok((cert, key_pair))
}

fn install_to_windows() {
    let _ = run_hidden_command("certutil", &["-addstore", "-f", "Root", "care_children_ca.crt"]);
}

fn setup_ssl_ca() -> Result<(), Box<dyn std::error::Error>> {
    let key_pair = rcgen::KeyPair::generate()?;

    let mut params = CertificateParams::default();
    let mut dn = DistinguishedName::new();
    dn.push(DnType::CommonName, "Care Children System CA");
    dn.push(DnType::OrganizationName, "CareChildrenSystem");
    params.distinguished_name = dn;

    params.is_ca = IsCa::Ca(BasicConstraints::Unconstrained);
    params.key_usages = vec![
        KeyUsagePurpose::KeyCertSign,
        KeyUsagePurpose::DigitalSignature,
        KeyUsagePurpose::CrlSign,
    ];
    let cert = params.self_signed(&key_pair)?;
    let cert_pem = cert.pem();
    let key_pem = key_pair.serialize_pem();

    fs::write("ca.crt", &cert_pem)?;
    fs::write("ca.key", &key_pem)?;

    Command::new("certutil")
        .args(&["-addstore", "-f", "Root", "care_children_ca.crt"])
        .status()?;

    println!("[SSL] Sertifikat Induk berhasil diinstal ke sistem.");
    Ok(())
}

fn install_root_cert_to_windows() {
    let cert_path = "care_children_ca.crt";
    let status = run_hidden_command("certutil", &["-addstore", "-f", "Root", cert_path]);
    
    match status {
        Ok(s) if s.success() => println!("[SSL] Sertifikat berhasil dipercaya oleh Windows."),
        _ => println!("[SSL] Gagal menginstal sertifikat. Pastikan jalankan sebagai Admin."),
    }
}

