struct Guard {
    is_guard_active: bool,
    is_visible: bool,
    password_admin: String,
    unlock_input: String,
    is_running: bool,
    is_editing_password: bool,
    is_hard_locked: bool,
    new_domain: String,
    blacklist: Vec<BlacklistEntry>,
    temp_blacklist: Vec<BlacklistEntry>,
    current_page: Page,
    is_showing_edit_popup: bool,
    selected_for_delete: Vec<i32>,
    has_deleted: bool,
    server_stop_signal: Arc<AtomicBool>,
    unlock_hotkey_id: u32,
    hotkey_manager: global_hotkey::GlobalHotKeyManager,
    last_toggle: std::time::Instant,
}

impl Default for Guard {
    fn default() -> Self {
        let (pass, list) = load_data_from_db();

        let manager = GlobalHotKeyManager::new().ok();
        let mut hotkey_id = 0;

        if let Some(ref m) = manager {
            let hotkey = HotKey::new(Some(Modifiers::SHIFT | Modifiers::CONTROL), Code::KeyL);
            if let Ok(_) = m.register(hotkey) {
                hotkey_id = hotkey.id();
            }
        }

        Self {
            is_guard_active: false,
            is_visible: true,
            password_admin: pass,
            unlock_input: String::new(),
            is_running: false,
            is_editing_password: false,
            is_hard_locked: true,
            new_domain: String::new(),
            blacklist: list,
            temp_blacklist: Vec::new(),
            current_page: Page::Overview,
            is_showing_edit_popup: false,
            selected_for_delete: Vec::new(),
            has_deleted: false,
            server_stop_signal: Arc::new(AtomicBool::new(false)),
            unlock_hotkey_id: hotkey_id,

            hotkey_manager: manager.expect("Hotkey Manager wajib ada untuk Stealth Mode"),
            last_toggle: std::time::Instant::now(),
        }
    }
}

